    private static QuizQuestion EuropaInDerWelt(Random r)
    {
        var f = EuropaWeltListe[r.Next(EuropaWeltListe.Length)];
        return new QuizQuestion
        {
            Id = NewId(), Subject = Subject.Geschichte, GradeLevel = GradeLevel.Klasse9,
            Topic = "Europa in der Welt", Type = QuestionType.MultipleChoice,
            Prompt = f.Frage, Options = f.Optionen, CorrectAnswers = new[] { f.Antwort }, Explanation = f.Erklaerung,
            HelpHint = "Europa stand seit der Frühen Neuzeit über Handel und Diplomatie in engem Austausch mit Kulturen wie China oder dem Osmanischen Reich - um 1900 prägten zunehmend imperiale Machtverhältnisse diese Beziehungen."
        };
    }

